1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block still life unchanged", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should transform a vertical blinker into a horizontal blinker", () => {
21	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
22	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(expected));
26	  });
27	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
28	    const block3x3: Cell[] = [
29	      [0, 0], [1, 0], [2, 0],
30	      [0, 1], [1, 1], [2, 1],
31	      [0, 2], [1, 2], [2, 2],
32	    ];
33	    const result = nextGeneration(block3x3);
34	    expect(result).not.toContainEqual([1, 1]);
35	  });
36	  it.todo("should bring a dead cell with exactly 3 neighbors to life (reproduction)");
37	});
