1	export type Cell = [number, number];
2	
3	const key = (x: number, y: number): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number => {
12	  let count = 0;
13	  for (const [dx, dy] of NEIGHBOR_OFFSETS) {
14	    if (liveSet.has(key(x + dx, y + dy))) count++;
15	  }
16	  return count;
17	};
18	
19	const survives = (isLive: boolean, neighbors: number): boolean =>
20	  (isLive && (neighbors === 2 || neighbors === 3)) || (!isLive && neighbors === 3);
21	
22	const collectCandidates = (cells: Cell[]): Map<string, Cell> => {
23	  const candidates = new Map<string, Cell>();
24	  const addCandidate = (x: number, y: number): void => {
25	    candidates.set(key(x, y), [x, y]);
26	  };
27	  for (const [x, y] of cells) {
28	    addCandidate(x, y);
29	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
30	      addCandidate(x + dx, y + dy);
31	    }
32	  }
33	  return candidates;
34	};
35	
36	export const nextGeneration = (cells: Cell[]): Cell[] => {
37	  const liveSet = new Set<string>(cells.map(([x, y]) => key(x, y)));
38	  const candidates = collectCandidates(cells);
39	
40	  return Array.from(candidates).
41	    filter(([k, [x, y]]) => survives(liveSet.has(k), countLiveNeighbors(x, y, liveSet))).
42	    map(([, cell]) => cell);
43	};
